using System.Text.Json;
using ModelContextProtocol.Server;
using System.ComponentModel;

[McpServerResourceType]
public static class ConfigResources
{
    private static readonly Dictionary<string, object> AppConfig = new()
    {
        ["environment"] = "production",
        ["maxRetries"] = 3,
        ["timeoutSeconds"] = 30,
        ["features"] = new Dictionary<string, bool>
        {
            ["darkMode"] = true,
            ["betaFeatures"] = false
        }
    };

    [McpServerResource(UriTemplate = "config://app", Name = "App Config",
        MimeType = "application/json"),
     Description("Returns the current application configuration as JSON")]
    public static string GetAppConfig() =>
        JsonSerializer.Serialize(AppConfig, new JsonSerializerOptions { WriteIndented = true });

    [McpServerResource(UriTemplate = "config://app/{section}", Name = "Config Section",
        MimeType = "application/json"),
     Description("Returns a specific configuration section by name")]
    public static string GetConfigSection(string section)
    {
        if (AppConfig.TryGetValue(section, out var value))
            return JsonSerializer.Serialize(value, new JsonSerializerOptions { WriteIndented = true });

        return JsonSerializer.Serialize(new { error = $"Section '{section}' not found" });
    }
}

using ModelContextProtocol.Server;
using System.ComponentModel;

[McpServerToolType]
public static class ConfigTools
{
    [McpServerTool, Description("Lists all available configuration keys")]
    public static string ListConfigKeys() =>
        string.Join(", ", new[] { "environment", "maxRetries", "timeoutSeconds", "features" });

    [McpServerTool, Description("Checks whether a feature flag is currently enabled")]
    public static string CheckFeatureFlag(
        [Description("Name of the feature flag to check (e.g. darkMode, betaFeatures)")] string flagName)
    {
        var flags = new Dictionary<string, bool>
        {
            ["darkMode"] = true,
            ["betaFeatures"] = false
        };

        if (flags.TryGetValue(flagName, out var enabled))
            return $"Feature '{flagName}' is {(enabled ? "enabled" : "disabled")}";

        return $"Feature flag '{flagName}' not found. Available: {string.Join(", ", flags.Keys)}";
    }
}

