var builder = WebApplication.CreateBuilder(args);

builder.Services.AddMcpServer(options =>
    {
        options.ServerInfo = new() { Name = "ConfigMcpServer", Version = "1.0.0" };
        options.ServerInstructions = "Provides application configuration data and feature flag status.";
    })
    .WithHttpTransport()
    .WithToolsFromAssembly()
    .WithResourcesFromAssembly();

var app = builder.Build();

app.MapMcp();
app.MapGet("/health", () => "ok");

app.Run();

